This is my code:

	from promise import Promise
	from threading import Timer
	from time import sleep


	class MyClass:
	    def __init__(self):
		self.p = None

	    def get_promise(self):
		self.p = Promise()

		def reject():
		    self.p.reject(Exception("qwe"))

		def resolve():
		    self.p.fulfill("asd")

		Timer(3, reject).start()
